  1	/* eslint-disable @typescript-eslint/no-explicit-any */
  2	import * as React from 'react';
  3	import cx from 'classnames';
  4	import Linkify from 'react-linkify';
  5	import { useTranslation } from 'react-i18next';
  6	import { CopyToClipboard as CTC } from 'react-copy-to-clipboard';
  7	import { Tooltip } from '@patternfly/react-core';
  8	import { CopyIcon } from '@patternfly/react-icons/dist/esm/icons/copy-icon';
  9	import { ExternalLinkAltIcon } from '@patternfly/react-icons/dist/esm/icons/external-link-alt-icon';
 10	import { ALL_NAMESPACES_KEY } from '../../consts';
 11	
 12	// Kubernetes "dns-friendly" names match
 13	// [a-z0-9]([-a-z0-9]*[a-z0-9])?  and are 63 or fewer characters
 14	// long. This pattern checks the pattern but not the length.
 15	//
 16	// Don't capture anything in legalNamePattern, since it's used
 17	// in expressions like
 18	//
 19	//    new RegExp("PREFIX" + legalNamePattern.source + "(SUFFIX)")
 20	//
 21	// And it's ok for users to make assumptions about capturing groups.
 22	
 23	export const legalNamePattern = /[a-z0-9](?:[-a-z0-9]*[a-z0-9])?/;
 24	
 25	const basePathPattern = new RegExp(
 26	  `^/?${(window as any).SERVER_FLAGS.basePath}`,
 27	);
 28	
 29	export const namespacedPrefixes = [
 30	  '/api-resource',
 31	  '/k8s',
 32	  '/operatorhub',
 33	  '/operatormanagement',
 34	  '/operators',
 35	  '/details',
 36	  '/search',
 37	  '/status',
 38	];
 39	
 40	export const stripBasePath = (path: string): string =>
 41	  path.replace(basePathPattern, '/');
 42	
 43	export const getNamespace = (path: string): string => {
 44	  path = stripBasePath(path);
 45	  const split = path.split('/').filter((x) => x);
 46	
 47	  if (split[1] === 'all-namespaces') {
 48	    return ALL_NAMESPACES_KEY;
 49	  }
 50	
 51	  let ns: string;
 52	  if (
 53	    split[1] === 'cluster' &&
 54	    ['namespaces', 'projects'].includes(split[2]) &&
 55	    split[3]
 56	  ) {
 57	    ns = split[3];
 58	  } else if (split[1] === 'ns' && split[2]) {
 59	    ns = split[2];
 60	  } else {
 61	    return;
 62	  }
 63	
 64	  const match = ns.match(legalNamePattern);
 65	  return match && match.length > 0 && match[0];
 66	};
 67	
 68	export const getURLSearchParams = () => {
 69	  const all: any = {};
 70	  const params = new URLSearchParams(window.location.search);
 71	
 72	  for (const [k, v] of params.entries()) {
 73	    all[k] = v;
 74	  }
 75	
 76	  return all;
 77	};
 78	
 79	export const ExternalLink: React.FC<ExternalLinkProps> = ({
 80	  children,
 81	  href,
 82	  text,
 83	  additionalClassName = '',
 84	  dataTestID,
 85	  stopPropagation,
 86	}) => (
 87	  <a
 88	    className={cx('co-external-link', additionalClassName)}
 89	    href={href}
 90	    target="_blank"
 91	    rel="noopener noreferrer"
 92	    data-test-id={dataTestID}
 93	    {...(stopPropagation ? { onClick: (e) => e.stopPropagation() } : {})}
 94	  >
 95	    {children || text}
 96	  </a>
 97	);
 98	
 99	// Opens link with copy-to-clipboard
100	
101	export const ExternalLinkWithCopy: React.FC<ExternalLinkWithCopyProps> = ({
102	  link,
103	  text,
104	  additionalClassName,
105	  dataTestID,
106	}) => {
107	  const [copied, setCopied] = React.useState(false);
108	
109	  const { t } = useTranslation('plugin__pipelines-console-plugin');
110	  const tooltipText = copied
111	    ? t('Copied to clipboard')
112	    : t('Copy to clipboard');
113	  const tooltipContent = [
114	    <span className="co-nowrap" key="nowrap">
115	      {tooltipText}
116	    </span>,
117	  ];
118	
119	  return (
120	    <div className={cx(additionalClassName)}>
121	      <a
122	        href={link}
123	        target="_blank"
124	        rel="noopener noreferrer"
125	        data-test-id={dataTestID}
126	      >
127	        {text ?? link}
128	        <span className="co-icon-nowrap">
129	          &nbsp;
130	          <span className="co-external-link-with-copy__icon co-external-link-with-copy__externallinkicon">
131	            <ExternalLinkAltIcon />
132	          </span>
133	        </span>
134	      </a>
135	      <span className="co-icon-nowrap">
136	        <Tooltip
137	          content={tooltipContent}
138	          trigger="click mouseenter focus"
139	          exitDelay={1250}
140	        >
141	          <CTC text={link} onCopy={() => setCopied(true)}>
142	            <span
143	              onMouseEnter={() => setCopied(false)}
144	              className="co-external-link-with-copy__icon co-external-link-with-copy__copyicon"
145	            >
146	              <CopyIcon />
147	              <span className="pf-v6-u-screen-reader">
148	                {t('Copy to clipboard')}
149	              </span>
150	            </span>
151	          </CTC>
152	        </Tooltip>
153	      </span>
154	    </div>
155	  );
156	};
157	
158	// Open links in a new window and set noopener/noreferrer.
159	export const LinkifyExternal: React.FC<{ children: React.ReactNode }> = ({
160	  children,
161	}) => (
162	  <Linkify properties={{ target: '_blank', rel: 'noopener noreferrer' }}>
163	    {children}
164	  </Linkify>
165	);
166	LinkifyExternal.displayName = 'LinkifyExternal';
167	
168	type ExternalLinkProps = {
169	  href: string;
170	  text?: React.ReactNode;
171	  additionalClassName?: string;
172	  dataTestID?: string;
173	  stopPropagation?: boolean;
174	};
175	
176	type ExternalLinkWithCopyProps = {
177	  link: string;
178	  text?: string;
179	  dataTestID?: string;
180	  additionalClassName?: string;
181	};

